import React, { useState } from 'react';
import axios from 'axios';

function NoteForm({ fetchNotes }) {
  const [form, setForm] = useState({ title: '', content: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault(); // Prevent page refresh
    if (!form.title || !form.content) return alert("Please fill in both fields");

    setIsSubmitting(true);
    try {
      await axios.post('http://localhost:5001/api/notes', form);
      fetchNotes();
      setForm({ title: '', content: '' });
    } catch (err) {
      console.error("Failed to add note", err);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="form-container">
      <form className="note-form" onSubmit={handleSubmit}>
        <h2 className="form-title">Create New Note</h2>

        <div className="input-group">
          <label>Title</label>
          <input
            type="text"
            placeholder="e.g., Kubernetes Pod Lifecycle"
            value={form.title}
            onChange={e => setForm({ ...form, title: e.target.value })}
            className="form-input"
          />
        </div>

        <div className="input-group">
          <label>Content</label>
          <textarea
            placeholder="Write your thoughts or technical snippets here..."
            value={form.content}
            onChange={e => setForm({ ...form, content: e.target.value })}
            className="form-textarea"
            rows="4"
          />
        </div>

        <button 
          type="submit" 
          className="submit-btn" 
          disabled={isSubmitting}
        >
          {isSubmitting ? "Saving..." : "Add to Vault"}
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <line x1="12" y1="5" x2="12" y2="19"></line>
            <line x1="5" y1="12" x2="19" y2="12"></line>
          </svg>
        </button>
      </form>
    </div>
  );
}

export default NoteForm;
